namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^\d{6,10}$", ErrorMessage = "Student ID must be 6-10 digits.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "English", Abbreviation = "ENG" },
        new() { Id = 4, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses;

    public CatalogService()
    {
        _courses =
        [
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, data structures, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Bob Martinez", InstructorBio = "Dr. Martinez specializes in algorithm optimization and competitive programming. He previously worked at Google Research before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, CourseCode = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, query optimization, and introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Carol Singh", InstructorBio = "Dr. Singh is an expert in distributed databases and has contributed to several open-source database projects.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, CourseCode = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. David Park", InstructorBio = "Dr. Park is an award-winning mathematics educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues and eigenvectors. Applications in data science and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Eva Johnson", InstructorBio = "Dr. Johnson's research focuses on numerical linear algebra and its applications in machine learning.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, CourseCode = "ENG 101", Title = "College Composition", Description = "Develop academic writing skills through essays, research papers, and peer review. Emphasis on argumentation and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. Frank Williams", InstructorBio = "Prof. Williams is a published author and has taught writing at the university level for over 20 years.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 7, CourseCode = "ENG 220", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present, exploring themes of identity, freedom, and social change.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Grace Thompson", InstructorBio = "Dr. Thompson specializes in 20th-century American fiction and has published two books on the Harlem Renaissance.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 8, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed 9:00–9:50 AM, Fri Lab 1:00–3:00 PM", InstructorName = "Dr. Henry Liu", InstructorBio = "Dr. Liu is an experimental physicist whose research involves quantum optics and precision measurement.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, CourseCode = "PHYS 210", Title = "Modern Physics", Description = "Introduction to special relativity, quantum mechanics, atomic and nuclear physics. Prerequisites: PHYS 101, MATH 151.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Irene Novak", InstructorBio = "Dr. Novak conducts research in particle physics and has collaborated with CERN on multiple experiments.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 10, CourseCode = "HIST 101", Title = "World Civilizations", Description = "Global history from ancient civilizations through the modern era, examining political, economic, and cultural developments.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. James O'Brien", InstructorBio = "Dr. O'Brien is a historian specializing in comparative world history with fieldwork experience across four continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

