@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@course.Description[..Math.Min(120, course.Description.Length)]…</p>
                </div>
                <div class="card-footer">
                    <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group mb-4">
    @foreach (var dept in _departments)
    {
        <a href="/courses?departmentId=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Abbreviation</strong> — @dept.Name
        </a>
    }
</div>

<div class="mt-3">
    <a href="/courses" class="btn btn-outline-primary me-2">Browse All Courses</a>
    <a href="/enroll" class="btn btn-outline-success">Enrollment Request</a>
</div>

@code {
    private List<Course> _featuredCourses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featuredCourses = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetDepartments();
    }
}

@page "/courses"
@rendermode InteractiveServer
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject NavigationManager Nav

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted">Showing @_courses.Count course(s)</p>
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in _courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Department> _departments = [];
    private List<Course> _courses = [];

    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string SearchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; RefreshCourses(); }
    }

    private int SelectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; RefreshCourses(); }
    }

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();

        // Check for departmentId query parameter
        var uri = Nav.ToAbsoluteUri(Nav.Uri);
        if (Microsoft.AspNetCore.WebUtilities.QueryHelpers.ParseQuery(uri.Query)
                .TryGetValue("departmentId", out var deptIdValue) &&
            int.TryParse(deptIdValue, out var deptId))
        {
            _selectedDepartmentId = deptId;
        }

        RefreshCourses();
    }

    private void RefreshCourses()
    {
        _courses = Catalog.GetCourses(
            string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm,
            _selectedDepartmentId > 0 ? _selectedDepartmentId : null);
    }
}

