@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject NavigationManager Nav

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will receive confirmation via your university email.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
           <strong>@_courses.FirstOrDefault(c => c.Id == _model.CourseId)?.Title</strong>
           has been received. You will be notified of your enrollment status.</p>
    </div>
    <a href="/courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" method="post">
        <DataAnnotationsValidator />
        <AntiforgeryToken />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="_model.StudentName" />
            <ValidationMessage For="() => _model.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" placeholder="e.g. 12345678" />
            <ValidationMessage For="() => _model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> _courses = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        _submitted = true;
    }
}

